function getState(){try{return localStorage.getItem('oc_state')||'georgia';}catch(e){return 'georgia';}}
function stateLabel(s){return s==='california'?'California':'Georgia';}

function filterByState(d,state){
  return d.filter(function(f){
    var st=f.st||'global';
    return !st||st==='global'||st===state;
  });
}

function sortFAQs(d){
  return d.slice().sort(function(a,b){
    return (a.o==null?99:a.o)-(b.o==null?99:b.o);
  });
}

function groupByCat(d){
  var g={};
  d.forEach(function(f){
    if(!f.c)return;
    if(!g[f.c])g[f.c]=[];
    g[f.c].push(f);
  });
  return g;
}

function escHtml(s){
  return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

function highlight(text,q){
  if(!q||!q.trim())return escHtml(text);
  var e=q.trim().replace(/[.*+?^${}()|[\]\\]/g,'\\$&');
  return escHtml(text).replace(new RegExp('('+e+')','gi'),'<span class="oc-fqi-hl">$1</span>');
}

